 using Runtime.Script;
 using TradeApi.Trading;
 using TradeApi.History;
 using System;
 using System.Linq;
 
 namespace TestEnv
    {
        public class GetExample : StrategyBuilder
        {
            public GetExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "GetExample";
                #endregion
            }
            
            public override void Init()
            {
                var timeRequest = new TimeHistoricalRequest(InstrumentsManager.Current, HistoryDataSeries.HistoricalRequest.DataType, Period.Minute, 1);
                var interval = new Interval(DateTime.UtcNow.AddDays(-2), DateTime.UtcNow);
                HistoricalDataManager.OnLoaded += this.HistoricalDataManager_OnLoaded;
                HistoricalDataManager.Get(timeRequest, interval);
            }
            private void HistoricalDataManager_OnLoaded(HistoricalData loadedHistoricalData)
            {
                if (loadedHistoricalData != null)
                {
                    for (int i = loadedHistoricalData.Count - 1; i >= 0; i--)
                    {
                        var open = loadedHistoricalData.GetValue(PriceType.Open, i);
                        var high = loadedHistoricalData.GetValue(PriceType.High, i);
                        var low = loadedHistoricalData.GetValue(PriceType.Low, i);
                        var close = loadedHistoricalData.GetValue(PriceType.Close, i);
                        Notification.Print(string.Format("Open: {0}, High: {1}, Low: {2}, Close: {3}", open, high, low, close));
                    }
                }
            }

            public override void Update(TickStatus args)
            {
            
            }
        }
    }

 using Runtime.Script;
 using TradeApi.Trading;
 using TradeApi.History;
 using System;
 using System.Linq;
 
 namespace TestEnv
    {
        public class ChangeIntervalExample : StrategyBuilder
        {
            public ChangeIntervalExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "ChangeIntervalExample";
                #endregion
            }
            
            public Interval interval;
            public HistoricalData loadedHistoricalData;
            
            public override void Init()
            {
                var timeRequest = new TimeHistoricalRequest(InstrumentsManager.Current, HistoryDataSeries.HistoricalRequest.DataType, Period.Minute, 1);
                interval = new Interval(DateTime.UtcNow.AddDays(-2), DateTime.UtcNow);
                HistoricalDataManager.OnLoaded += this.HistoricalDataManager_OnLoaded;
                HistoricalDataManager.Get(timeRequest, interval);
            }
            
            private void HistoricalDataManager_OnLoaded(HistoricalData loadedHistoricalData)
            {
                this.loadedHistoricalData = loadedHistoricalData;
                if (loadedHistoricalData != null)
                {
                    for (int i = loadedHistoricalData.Count - 1; i >= 0; i--)
                    {
                        var open = loadedHistoricalData.GetValue(PriceType.Open, i);
                        var high = loadedHistoricalData.GetValue(PriceType.High, i);
                        var low = loadedHistoricalData.GetValue(PriceType.Low, i);
                        var close = loadedHistoricalData.GetValue(PriceType.Close, i);
                        Notification.Print(string.Format("Open: {0}, High: {1}, Low: {2}, Close: {3}", open, high, low, close));
                    }
                }
            }

            public override void Update(TickStatus args)
            {
                 if (HistoryDataSeries.GetTimeUtc(HistoryDataSeries.Count - 1) < tickData.GetTimeUtc(tickData.Count - 1))
                 {
                     interval = new Interval(interval.FromUtc.AddDays(-1), DateTime.UtcNow);
                     HistoricalDataManager.ChangeInterval(loadedHistoricalData, interval);
                 }
            }
        }
    }

 using Runtime.Script;
 using TradeApi.Trading;
 using TradeApi.History;
 using System;
 using System.Linq;
 
 namespace TestEnv
    {
        public class RemoveExample : StrategyBuilder
        {
            public RemoveExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "RemoveExample";
                #endregion
            }
            
            private HistoricalData historicalData;
            private bool isLoaded = false;
            
            public override void Init()
            {
                var timeRequest = new TimeHistoricalRequest(InstrumentsManager.Current, HistoryDataSeries.HistoricalRequest.DataType, Period.Minute, 1);
                interval = new Interval(DateTime.UtcNow.AddDays(-2), DateTime.UtcNow);
                HistoricalDataManager.OnLoaded += this.HistoricalDataManager_OnLoaded;
                HistoricalDataManager.OnRemoved += this.HistoricalDataManager_OnRemoved;
                HistoricalDataManager.Get(timeRequest, interval);
            }
            
            private void HistoricalDataManager_OnLoaded(HistoricalData historicalData)
            {
                 this.historicalData = historicalData;
                 this.isLoaded = true;
                 Notification.Print($"History data is loaded");
            }
            
            private void HistoricalDataManager_OnRemoved(HistoricalData historicalData)
            {
                 this.historicalData = null;
                 this.isLoaded = false;
                 Notification.Print($"History data is removed");
            }

            public override void Update(TickStatus args)
            {
                 if (this.isLoaded && HistoryDataSeries.GetTimeUtc(HistoryDataSeries.Count - 1) < tickData.GetTimeUtc(historicalData.Count - 1))
                 {                     
                     HistoricalDataManager.Remove(historicalData);
                 }
            }
        }
    }

