 using Runtime.Script;
 using TradeApi.Trading;
 using TradeApi.History;
 using System;
 
 namespace TestEnv
    {
        public class FromUtcExample : StrategyBuilder
        {
            public FromUtcExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "FromUtcExample";
                #endregion
            }
            
            HistoricalData data;
            Interval interval;
            
            public override void Init()
            {
                    var newData = new TimeHistoricalRequest(instrument: InstrumentsManager.Current, dataType: DataType.Ask, period: Period.Minute, value: 15);
                    var from = DateTime.UtcNow.AddDays(-1);
                    var to = DateTime.UtcNow;
                    interval =  new Interval(fromUtc: from, toUtc: to);   
                    data = HistoricalDataManager.Get(newData, interval);
            }

            public override void Update(TickStatus args)
            {
               if (args == TickStatus.IsBar)
                 {                      
                    if (HistoryDataSeries.GetTimeUtc(data.Count - 1) < interval.FromUtc)
                    {
                         var newInterval = new Interval(fromUtc: HistoryDataSeries.GetTimeUtc(data.Count - 1), toUtc: DateTime.UtcNow);
                         HistoricalDataManager.ChangeInterval(data, newInterval);
                    }
                 }
            }
        }
    }

