       {
           public GetTimeValueExample()
           : base()
           {
               #region Initialization
               Credentials.ProjectName = "GetTimeValueExample";
               #endregion
           }
           
           public override void Init()
           {          
           
           }
           
           public override void Update(TickStatus args)
           {
           
           }
           
           public override void OnPaintChart(object sender, PaintChartEventArgs args)
           {
                var mainWidow = ChartSource.GetAllWindows().Find(win => win.IsMainWindow);
                
                var windowRectUpperPoint = mainWidow.WindowRectangle.Location;
                var windowHighestPriceEdge = ChartSource.PointToChart(windowRectUpperPoint);
                var timeValueHighest = ChartSource.GetTimeValue(windowHighestPriceEdge, mainWidow.WindowNumber);
                PointF dividerLineStart = ChartSource.GetChartPoint(timeValueHighest, mainWidow.WindowNumber);
                
                var windowLowestPriceEdge = ChartSource.PointToChart(new Point(mainWidow.WindowRectangle.Left, mainWidow.WindowRectangle.Bottom));
                var timeValueLowest = ChartSource.GetTimeValue(windowLowestPriceEdge, mainWidow.WindowNumber);
                PointF dividerLineEnd = ChartSource.GetChartPoint(timeValueLowest, mainWidow.WindowNumber);
                
                args.Graphics.DrawLine(new Pen(Color.Orange, 2), dividerLineStart, dividerLineEnd);
                ChartSource.GUIRefresh();
            }
       }
   }

