 using Runtime.Script;
 using TradeApi.Indicators;
 using System.Windows.Forms;
 using System;
 using System.Drawing;
 using TradeApi.History;
 
 namespace TestEnv
    {
        public class ChartSourceExample : IndicatorBuilder
        {
            public ChartSourceExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "ChartSourceExample";
                #endregion

                Lines.Set("ChartSourceExample");

                base.SeparateWindow = false;
            }
            
            TextBox CustomText;
            Control chrt;
 
            public override void Init()
            {
                 CustomText = new TextBox();
                 CustomText.Location = new Point(25, 40);

                 chrt = this.ChartSource.GetChartControl() as Control;

                 Action add = () =>
                 {
                     chrt.Controls.Add(CustomText);
                 };

                 chrt.Invoke(add);
            }

            public override void Update(TickStatus args)
            {
                 CustomText.Text = this.HistoryDataSeries.GetValue(PriceType.Close).ToString();
            }
            
            public override void Complete()
             {
                 Action remove = () =>
                 {
                     chrt.Controls.Remove(CustomText);
                 };

                 chrt.Invoke(remove);
             }
        }
    }

