                     request = new OrderRequest(OrderType.Market, instrument, AccountManager.Current, OrderSide.Buy, instrument.MinimalLot(ProductType.General));
            }

            public override void Update(TickStatus args)
            {
               if (args == TickStatus.IsBar && request != null)
                 {
                     var futures = InstrumentsManager.Current as FuturesInstrument;
                     if(futures.LastTradeDate < futures.FirstTradeDate)
                         OrdersManager.Send(request);                        
                 }
            }
        }
    }

