 using Runtime.Script;
 using TradeApi.History;
 using System;
 using TradeApi.Indicators;
 
 namespace TestEnv
    {
        public class HistoricalDataManagerExample : IndicatorBuilder
        {
            public HistoricalDataManagerExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "HistoricalDataManagerExample";
                #endregion

                Lines.Set("HistoricalDataManagerExample");

                base.SeparateWindow = false;
            }
            
            [InputParameter(InputType.Numeric, "Period of Moving Average", 0)]
            [SimpleNumeric(1D, 99999D)]
            public int MAPeriod = 1;
            
            HistoricalData LoadedHistory;
            
            public override void Init()
            {
                 var historicalReq = new TimeHistoricalRequest(InstrumentsManager.Current, HistoryDataSeries.HistoricalRequest.DataType, Period.Day, MAPeriod);
                 HistoricalDataManager.OnLoaded += this.HistoricalDataManager_OnLoaded;
                 HistoricalDataManager.Get(historicalReq, new Interval(DateTime.UtcNow.AddDays(-1), DateTime.UtcNow));
            }
            
            private void HistoricalDataManager_OnLoaded(HistoricalData loadedHistoricalData)
            {
                LoadedHistory = loadedHistoricalData;
                if (LoadedHistory != null)
                {
                    for (int i = LoadedHistory.Count - 1; i >= 0; i--)
                    {
                        var open = LoadedHistory.GetValue(PriceType.Open, i);
                        var high = LoadedHistory.GetValue(PriceType.High, i);
                        var low = LoadedHistory.GetValue(PriceType.Low, i);
                        var close = LoadedHistory.GetValue(PriceType.Close, i);
                        Notification.Print(string.Format("Open: {0}, High: {1}, Low: {2}, Close: {3}", open, high, low, close));
                    }
                }
            }

            public override void Update(TickStatus args)
            {
                 
            }
        }
    }

 using System;
 using Runtime.Script;
 using TradeApi.Indicators;
 
 namespace TestEnv
    {
        public class NotificationExample : IndicatorBuilder
        {
            public NotificationExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "NotificationExample";
                #endregion

                Lines.Set("NotificationExample");

                base.SeparateWindow = false;
            }
            
            public override void Init()
            {
                 const string SCRIPT_START = "script starts";
                 
                 switch (DateTime.UtcNow.DayOfWeek) {
                   case DayOfWeek.Monday:
                        Notification.Alert(SCRIPT_START);
                        break;
                   case DayOfWeek.Tuesday:
                        Notification.Comment(SCRIPT_START);
                        break;
                   case DayOfWeek.Wednesday:
                        Notification.Print(SCRIPT_START);
                        break;
                   case DayOfWeek.Thursday:
                        Notification.PlaySound("sound.wav");
                        break;  
                   default:
                        Notification.Alert(SCRIPT_START);
                        break;
                  }
            }

            public override void Update(TickStatus args)
            {
            
            }
        }
    }

