using System.Linq;

namespace TestEnv
   {
       public class CommentExample : StrategyBuilder
       {
           public CommentExample()
           : base()
           {
               #region Initialization
               Credentials.ProjectName = "CommentExample";
               #endregion
           }
           
           public override void Init()
           {
               var instrument = InstrumentsManager.Current;
               var ask = instrument.DayInfo.Ask;
               var offset = 100 * instrument.MinimalTickSize;
               var limitPrice = ask - offset;
               OrderRequest orderRequest = new OrderRequest(OrderType.Limit, instrument, AccountManager.Current, OrderSide.Buy, 1, limitPrice)
               {
                   Comment = "Test",
               };
           
               OrdersManager.OnPlace += OrdersManager_OnPlace;
               OrdersManager.Send(orderRequest);
           }
           private void OrdersManager_OnPlace(Order order)
           {
               Notification.Print(order.ID + " - " + order.Comment);
           }
           public override void Complete()
           {
               OrdersManager.OnPlace -= OrdersManager_OnPlace;
           }
       }
   }

