    public class BoundToIdExample : StrategyBuilder
    {
        public BoundToIdExample()
        : base()
        {
            #region Initialization
            Credentials.ProjectName = "BoundToIdExample";
            Credentials.Description = "BoundToId property Example";
            #endregion
        }

        public override void Init()
        {

        }

        public override void Update(TickStatus args)
        {
            var orders = OrdersManager.GetOrders(true);
            foreach (Order order in orders)
            {
                if (string.IsNullOrEmpty(order.BoundToId))
                    continue;

                Notification.Print($"Order {order.ID} is bound to order {order.BoundToId}");
                var position = PositionsManager.GetPositions().Where(x => x.OpenOrderID == order.BoundToId).FirstOrDefault();
                
                if (position != null)
                    Notification.Print($"Order {order.ID} is bound to position {position.ID}");
            }
        }
    }
}

