using Runtime.Script;
using TradeApi.Trading;
public class SuperPositionIdExample : StrategyBuilder
{
	private bool isOrderPlaced = false;

    public SuperPositionIdExample() : base()
    {
        #region Initialization
        Credentials.ProjectName = "SuperPositionIdExample";
        #endregion
    }

    public override void Init()
    {
        PositionsManager.OnOpen += OnOpenPosition;
    }

    public override void Update(TickStatus args)
    {
        if (args == TickStatus.IsBar && !isOrderPlaced)
        {
            var instrument = InstrumentsManager.Current;
            var account = AccountManager.Current;

            //Create market order with Product Type - Intraday
            OrderRequest orderRequest = new OrderRequest(OrderType.Market, instrument, account, OrderSide.Buy, 1);
            orderRequest.ProductType = ProductType.Intraday;
            OrdersManager.SendAsync(orderRequest, PlaceOrderCallback);
        }
    }

    private void PlaceOrderCallback(TradeResult tradeResult)
    {
        if (!tradeResult.HasError)
            isOrderPlaced = true;
    }

    private void OnOpenPosition(Position position)
    {
        bool isSubPosition = !string.IsNullOrEmpty(position.SuperPositionId);
        if (isSubPosition)
        {
            //Change Product Type from Intraday to Delivery for SubPosition
            position.ChangeProductType(ProductType.Delivery);
        }
        else
        {
            Notification.Print("It's SuperPosition or simple position");
        }
    }
}

using Runtime.Script;
using TradeApi.Trading;
public class ChangeProductTypeExample : StrategyBuilder
{
	private bool isOrderPlaced = false;

    public ChangeProductTypeExample() : base()
    {
        #region Initialization
        Credentials.ProjectName = "ChangeProductTypeExample";
        #endregion
    }

    public override void Init()
    {
        PositionsManager.OnOpen += OnOpenPosition;
    }

    public override void Update(TickStatus args)
    {
        if (args == TickStatus.IsBar && !isOrderPlaced)
        {
            var instrument = InstrumentsManager.Current;
            var account = AccountManager.Current;

            //Create market order with Product Type - Intraday
            OrderRequest orderRequest = new OrderRequest(OrderType.Market, instrument, account, OrderSide.Buy, 1);
            orderRequest.ProductType = ProductType.Intraday;
            OrdersManager.SendAsync(orderRequest, PlaceOrderCallback);
        }
    }

    private void PlaceOrderCallback(TradeResult tradeResult)
    {
        if (!tradeResult.HasError)
            isOrderPlaced = true;
    }

    private void OnOpenPosition(Position position)
    {
        bool isSubPosition = !string.IsNullOrEmpty(position.SuperPositionId);
        if (isSubPosition)
        {
            //Change Product Type from Intraday to Delivery for SubPosition
            position.ChangeProductType(ProductType.Delivery, 0.5);
        }
        else
        {
            Notification.Print("It's SuperPosition or simple position");
        }
    }
}

