 using Runtime.Script;
 using TradeApi.Trading;
 
 namespace TestEnv
    {
        public class OnOpenExample : StrategyBuilder
        {
            public OnOpenExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "OnOpenExample";
                #endregion
            }
            
            public override void Init()
            {
                PositionsManager.OnOpen += Show_Message;
            }
            
            private void Show_Message(Position position) 
            {
                 Notification.Print($"Position: {position.ID} is opened");
            }

            public override void Update(TickStatus args)
            {
               if (args == TickStatus.IsBar)
                 {
                   var newRequest = new OrderRequest(OrderType.Limit, InstrumentsManager.Current, AccountManager.Current, OrderSide.Buy, 1);
                   OrdersManager.Send(newRequest);
                 }
            }
            
            public override void Complete()
            {
                 PositionsManager.OnOpen -= Show_Message;
            }
        }
    }

 using Runtime.Script;
 using TradeApi.Trading;
 
 namespace TestEnv
    {
        public class OnCloseExample : StrategyBuilder
        {
            public OnCloseExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "OnCloseExample";
                #endregion
            }
            
            public override void Init()
            {
                PositionsManager.OnClose += Show_Message;
            }
            
            private void Show_Message(Position position) 
            {
                 Notification.Print($"Position: {position.ID} is closed");
            }

            public override void Update(TickStatus args)
            {
               if (args == TickStatus.IsBar)
                 {
                   var positions = PositionsManager.GetPositions(position => position.Side == PositionSide.Long);
                   positions.ForEach(position =>
                     {
                         PositionsManager.Close(position);
                     });
                 }
            }
            
            public override void Complete()
            {
                 PositionsManager.OnClose -= Show_Message;
            }
        }
    }

 using Runtime.Script;
 using TradeApi.Trading;
 using System;
 
 namespace TestEnv
    {
        public class CustomTradingHoursExample : StrategyBuilder
        {
            public CustomTradingHoursExample()
            : base()
            {
                #region Initialization
                Credentials.ProjectName = "CustomTradingHoursExample";
                #endregion
            }
            
            [InputParameter(InputType.DateTime, "Custom trading hours", 1)]
            public DateTime tradingHours;
            
            public override void Init()
            {
                 this.CustomTradingHours = tradingHours.ToLongDateString();
            }

            public override void Update(TickStatus args)
            {
                 if (DateTime.Parse(this.CustomTradingHours) < DateTime.UtcNow)
                     return;            
            }
        }
    }

